terraform.content:
resource "aws_kms_key" "{node_id}_key" {
  description             = "KMS key for {node_id} encryption at rest"
  enable_key_rotation     = true
  deletion_window_in_days = 7
}

resource "aws_db_instance" "{node_id}" {
  storage_encrypted = true
  kms_key_id        = aws_kms_key.{node_id}_key.arn
}

resource "aws_api_gateway_rest_api" "{node_id}_gateway" {
  name        = "{node_id}-auth-gateway"
  description = "Authentication gateway — blocks unauthenticated PUBLIC to PRIVATE access"
}

resource "aws_api_gateway_authorizer" "{node_id}_auth" {
  name          = "CognitoAuthorizer"
  rest_api_id   = aws_api_gateway_rest_api.{node_id}_gateway.id
  type          = "COGNITO_USER_POOLS"
  provider_arns = [aws_cognito_user_pool.main.arn]
}
